#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long cnt = 0;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            if(x==1) cnt++;
        }
        if(cnt==0) printf("0");
        else if(cnt==1) printf("-1");
        else printf("%lld", cnt);
        if(T) printf("\n");
    }
    return 0;
}

