import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        cnt = 0
        for _ in range(N):
            if int(next(it)) == 1:
                cnt += 1
        if cnt == 0:
            out.append('0')
        elif cnt == 1:
            out.append('-1')
        else:
            out.append(str(cnt))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

